return profiles.map((p, i) => ({
  json: {
    member_id: 'M' + String(i + 1).padStart(3, '0'),
    full_name: p.full_name,
    country: p.country,
    academic_level: p.academic_level,
    research_area: p.research_area,
    biography: p.biography,
    career_goals: p.career_goals,
    reason_for_joining: p.reason_for_joining,
    edge_case_flags: p.edge_case_flags.join(', ')
  }
}));

function tokenize(text) {
  return new Set((String(text || '')).toLowerCase().match(/[a-z0-9']+/g) || []);
}
function jaccard(a, b) {
  if (a.size === 0 && b.size === 0) return 0;
  let intersection = 0;
  for (const tok of a) if (b.has(tok)) intersection++;
  const union = a.size + b.size - intersection;
  return union === 0 ? 0 : intersection / union;
}

const rows = items.map(i => i.json);
const tokenSets = rows.map(r => tokenize(r.email_body));

const results = rows.map((row, idx) => {
  let maxSim = 0;
  let mostSimilarTo = null;
  for (let j = 0; j < rows.length; j++) {
    if (j === idx) continue;
    const sim = jaccard(tokenSets[idx], tokenSets[j]);
    if (sim > maxSim) { maxSim = sim; mostSimilarTo = rows[j].member_id; }
  }
  const similarityPercent = Math.round(maxSim * 1000) / 10;
  return {
    member_id: row.member_id,
    full_name: row.full_name,
    max_similarity_percent: similarityPercent,
    most_similar_to_member_id: mostSimilarTo,
    flagged_duplicate: similarityPercent > 30
  };
});

const flaggedCount = results.filter(r => r.flagged_duplicate).length;
const uniquenessScore = rows.length > 0 ? Math.round((1 - flaggedCount / rows.length) * 1000) / 10 : 100;
const avgSimilarity = results.length > 0 ? Math.round((results.reduce((s, r) => s + r.max_similarity_percent, 0) / results.length) * 10) / 10 : 0;
const variationScore = Math.round((100 - avgSimilarity) * 10) / 10;
const recommendation = flaggedCount > 0
  ? (flaggedCount + ' email(s) exceeded the 30% similarity threshold. Review the prompt for over-templated phrasing and add more profile-specific detail.')
  : 'No emails exceeded the 30% similarity threshold. Personalization variation looks healthy.';

return results.map(r => ({
  json: Object.assign({}, r, {
    run_uniqueness_score: uniquenessScore,
    run_variation_score: variationScore,
    run_recommendation: recommendation
  })
}));

const outreach = $('Read All Generated Outreach').all().map(i => i.json);
const dupes = $('Detect Duplicates').all().map(i => i.json);

function avg(nums) { return nums.length ? Math.round((nums.reduce((a, b) => a + b, 0) / nums.length) * 10) / 10 : 0; }
function countBy(arr, key) {
  const out = {};
  for (const item of arr) {
    const k = item[key] || 'Unknown';
    out[k] = (out[k] || 0) + 1;
  }
  return out;
}

const engagementScores = outreach.map(r => Number(r.engagement_score) || 0);
const avgEngagement = avg(engagementScores);

const categoryDistribution = countBy(outreach, 'classification');
const openDistribution = countBy(outreach, 'open_likelihood');
const academicLevelDistribution = countBy(outreach, 'academic_level');

const flaggedCount = dupes.filter(d => d.flagged_duplicate).length;
const duplicatePercent = dupes.length ? Math.round((flaggedCount / dupes.length) * 1000) / 10 : 0;

const totalRows = outreach.length;
const successRate = totalRows ? 100 : 0;

const edgeCaseRows = outreach.filter(r => r.edge_case_flags && String(r.edge_case_flags).trim() !== '');
const edgeCasePassRate = edgeCaseRows.length ? Math.round((edgeCaseRows.filter(r => r.subject && r.email_body).length / edgeCaseRows.length) * 1000) / 10 : 100;

const runId = 'RUN-' + new Date().toISOString();

const reportText = [
  'IAASSE W4 AI Persona Stress Test — Run ' + runId,
  '----------------------------------------------------',
  'Members processed: ' + totalRows + ' / 20',
  'Workflow success rate: ' + successRate + '%',
  'Average engagement score: ' + avgEngagement + ' / 100',
  'Category distribution: ' + JSON.stringify(categoryDistribution),
  'Open-likelihood distribution: ' + JSON.stringify(openDistribution),
  'Academic level distribution: ' + JSON.stringify(academicLevelDistribution),
  'Duplicate-flagged emails (>30% similarity): ' + flaggedCount + ' (' + duplicatePercent + '%)',
  'Uniqueness score: ' + (dupes[0] ? dupes[0].run_uniqueness_score : 'n/a'),
  'Variation score: ' + (dupes[0] ? dupes[0].run_variation_score : 'n/a'),
  'Edge case rows tested: ' + edgeCaseRows.length + ', pass rate: ' + edgeCasePassRate + '%',
  'Recommendation: ' + (dupes[0] ? dupes[0].run_recommendation : 'n/a')
].join('\n');

return [{
  json: {
    run_id: runId,
    timestamp: new Date().toISOString(),
    members_processed: totalRows,
    workflow_success_rate: successRate,
    avg_engagement_score: avgEngagement,
    category_distribution: JSON.stringify(categoryDistribution),
    open_likelihood_distribution: JSON.stringify(openDistribution),
    academic_level_distribution: JSON.stringify(academicLevelDistribution),
    duplicate_flagged_count: flaggedCount,
    duplicate_percent: duplicatePercent,
    edge_case_rows_tested: edgeCaseRows.length,
    edge_case_pass_rate: edgeCasePassRate,
    report_text: reportText
  }
}];

