Academic Level: {{ $json.academic_level }}
Research Area: {{ $json.research_area }}
Biography: {{ $json.biography || "(not provided)" }}
Career Goals: {{ $json.career_goals || "(not provided)" }}
Reason for Joining: {{ $json.reason_for_joining || "(not provided)" }}

